mapper.select:
SELECT g.id, g.title, g.description, g.category_id AS categoryId, g.seller_id AS sellerId, g.price, g.original_price AS originalPrice, g.condition_level AS conditionLevel, g.images, g.location, g.status, g.view_count AS viewCount, g.favorite_count AS favoriteCount, g.is_auction AS isAuction, g.ai_estimated_price AS aiEstimatedPrice, g.created_at AS createdAt, g.updated_at AS updatedAt,
(CASE WHEN g.title LIKE CONCAT('%',#{kw},'%') THEN 10 ELSE 0 END + CASE WHEN c.name LIKE CONCAT('%',#{kw},'%') THEN 6 ELSE 0 END + CASE WHEN g.description LIKE CONCAT('%',#{kw},'%') THEN 3 ELSE 0 END + CASE WHEN g.location LIKE CONCAT('%',#{kw},'%') THEN 2 ELSE 0 END) AS relevance
0 AS relevance
FROM goods g LEFT JOIN categories c ON g.category_id = c.id WHERE g.status IN (1, 4)
AND (
(g.title LIKE CONCAT('%',#{kw},'%') OR g.description LIKE CONCAT('%',#{kw},'%') OR g.location LIKE CONCAT('%',#{kw},'%') OR c.name LIKE CONCAT('%',#{kw},'%'))
)
AND g.category_id = #{categoryId}
AND g.price >= #{minPrice}
AND g.price <= #{maxPrice}
AND g.condition_level >= #{conditionLevel}
ORDER BY relevance DESC, g.created_at DESC LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM goods g
LEFT JOIN categories c ON g.category_id = c.id
WHERE g.status IN (1, 4)

    AND (

            (g.title LIKE CONCAT('%',#{kw},'%')
            OR g.description LIKE CONCAT('%',#{kw},'%')
            OR g.location LIKE CONCAT('%',#{kw},'%')
            OR c.name LIKE CONCAT('%',#{kw},'%'))

    )


    AND g.category_id = #{categoryId}


    AND g.price >= #{minPrice}


    AND g.price <= #{maxPrice}


    AND g.condition_level >= #{conditionLevel}
